import logo from "./FinTrack-Logo.png";
import "./Navbar.css";
import { NavLink } from "react-router-dom";


function Navbar() {
  return (
    <nav className="navbar">
      <div className="elements">

        <div className="logo">
          <img src={logo} alt="FinTrack Logo" className="logo" />
        </div>
        <div className="nav-right">
            <button
                className="btn-theme"
                id="themeToggle"
                onClick={toggleTheme}
            >
                {
                    theme === "dark-purple"
                        ? "✨ Light Mode"
                        : "🔮 Dark Mode"
                }
            </button>

            <a
                href="#authSection"
                onClick={() => setActiveTab("login")}
                className="btn btn-secondary"
                style={{
                    padding: "8px 16px",
                    fontSize: "0.85rem"
                }}
            >
                Sign In
            </a>
        </div>
        <NavLink
          to="/dashboard"
          className={({ isActive }) =>
            isActive ? "nav-btn active" : "nav-btn"
          }
        >
          Dashboard
        </NavLink>

        <NavLink
          to="/transactions"
          className={({ isActive }) =>
            isActive ? "nav-btn active" : "nav-btn"
          }
        >
          Transactions
        </NavLink>

        <NavLink
          to="/analytics"
          className={({ isActive }) =>
            isActive ? "nav-btn active" : "nav-btn"
          }
        >
          Analytics
        </NavLink>

      </div>
    </nav>
  );
}

export default Navbar;
